var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 부르자, 약속한 장소에서 기다리고 있겠다는 대답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"제 초대에 응해 주셔서 감사해요, 관리자님.","JPN":"招待に応じていただき、ありがとうございます。管理者様。","ENG":"Thank you for accepting my invitation, Administrator.","TWN":"管理者，謝謝你前來赴約。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"몽환의 해변은 어떠신가요? 이곳은 외부 세계로부터 철저히 유리된 공간이랍니다.","JPN":"夢幻の海辺はいかがですか？　ここは外の世界から一切隔絶された場所なんです。","ENG":"How do you like the midsummer's beach? This place is isolated from everything in the outside world.","TWN":"還喜歡這個夢幻海邊嗎？這裡可是完全與外界隔絕的空間。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"파도가 부서지는 소리, 모래가 밟히는 감촉, 은은하게 퍼지는 바다 냄새…….","JPN":"波が打ち寄せる音、砂を踏みしめる感触、ほのかに漂う潮の香り……","ENG":"The sound of crashing waves, the soft sand under my bare feet, and the smell of the ocean water...","TWN":"波浪拍打的聲音，腳踩沙子的觸感，隱約聞到的海的味道……"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"이곳에서라면 세상의 모든 근심과 걱정을 잠시 잊을 수 있겠죠.","JPN":"ここでならこの世の悩みや心配のすべてをしばし忘れていられます。","ENG":"It is a place where you can be carefree for a moment.","TWN":"在這裡感覺可以將一切煩惱暫時拋諸腦後。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"저도…… 그리고 당신도.","JPN":"私も……そして、あなたも。","ENG":"For me... and even for you.","TWN":"無論是對我……或是對你而言，都是如此。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"후후, 그러니까 긴장하지 않으셔도 괜찮아요.","JPN":"ふふ、ですから緊張なさらなくても大丈夫ですわ。","ENG":"Fu fu, so there is no need to be nervous.","TWN":"呵呵，所以你無須太過緊張。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"이렇게 작은 불씨지만, 서로가 서로에 대해 솔직해지기에는 충분히 밝으니까요.","JPN":"このような小さな火種ですが、お互いに率直になるには十分な明るさです。","ENG":"Even a small flame like this is bright enough for the two of us to become truthful with one another.","TWN":"雖然只是微微的火光，卻足以使我們坦誠相對。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"얼어붙은 시간에서 당신은 제 이정표가 되어주었죠.","JPN":"凍りついた時間の中で あなたは私の道しるべになってくださいました。","ENG":"When time froze, you became my beacon.","TWN":"在結凍的時間內，你成為我的指引。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"그러니 이번에는 제가 당신에게 도움이 되어드릴 차례에요.","JPN":"ですから今度は私がお手伝いします。","ENG":"Now, it is my turn to help you.","TWN":"所以現在換我來幫你吧。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"어떤 이야기든 괜찮아요.","JPN":"どんなお話でも結構ですわ。","ENG":"You can tell me anything.","TWN":"什麼都可以說，"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"슬픈 일이든, 기쁜 일이든…… 가슴 속에 담긴 이야기를 해주세요.","JPN":"悲しいことでも、嬉しいことでも……心の中で思っていることをお話しください。","ENG":"Something you are happy or sad about... Tell me what is inside your heart.","TWN":"無論是傷心的事，或是開心的事……把你心裡的事告訴我。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"제가 당신을 충분히 탐구할 수 있도록.","JPN":"私があなたをよく探究できるように。","ENG":"For it will give me enough time to study you.","TWN":"讓我可以充分地探索你。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"후후, 알고 있어요.","JPN":"ふふ、わかっておりますわ。","ENG":"Fu fu, I am aware.","TWN":"呵呵，我知道。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"이 곳에서의 찰나조차 결국 도피행에 지나지 않겠죠.","JPN":"ここでの刹那でさえ、逃避行にすぎないということは。","ENG":"That the time spent here will be nothing more than an escape.","TWN":"在這裡度過的時間，說到底只是在逃避現實而已。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"한 여름 밤의 꿈에서 깨어나면 저는 학회장으로서, 당신은 관리자로서 책임을 다하게 될 테니까요.","JPN":"真夏の夜の夢から覚めれば、私は学会長として、あなたは管理者として責任を果たすことになるでしょう。","ENG":"Once this summer dream ends, you and I will perform our responsibilities as the President and as the Administrator.","TWN":"因為從仲夏夜之夢醒過來後，我有我身為學會長，你有你身為管理者應盡的責任。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"하지만 그렇다고 이 순간이 의미 없다고 생각하지는 않아요.","JPN":"でも、そうだとしてもこの瞬間に意味がないとは思いません。","ENG":"However, that does not mean this moment is meaningless.","TWN":"但我不認為這段時間因此就沒有任何意義。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"그러니까 지금은…….","JPN":"ですから今は……","ENG":"So for now...","TWN":"所以現在……"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"지금은 그저 당신의 온기를 가까이서 느낄 수 있도록 품을 빌려주세요.","JPN":"今はただ、あなたの温もりを近くに感じられるように、胸をお貸しください。","ENG":"Allow me to fall into your arms so I can feel your warmth.","TWN":"請將你的懷抱借給我，我想要好好感受你的溫度。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_SPECIAL","text":{"KOREA":"……제가 됐다고 할 때까지. 계속.","JPN":"……私がいいというまで、ずっと。","ENG":"…Stay close to me... until I say it is enough.","TWN":"……在我說鬆開手之前，不能放開。"},"stage":{"bg":"FROZEN_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_SPECIAL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};